{"code": "import json

# Load female BRCA patients
brca_patients_result = locals()['var_functions.query_db:24']
if isinstance(brca_patients_result, str) and brca_patients_result.endswith('.json'):
    with open(brca_patients_result, 'r') as f:
        female_brca_patients = json.load(f)
else:
    female_brca_patients = brca_patients_result

# Extract patient barcodes and histological types
patient_data = []
for rec in female_brca_patients:
    # Extract patient barcode from Patient_description
    desc = rec.get('Patient_description', '')
    hist_type = rec.get('histological_type', 'Unknown')

    # Find TCGA barcode in description
    import re
    match = re.search(r'TCGA-[A-Z0-9-]+', desc)
    if match:
        barcode = match.group(0)
        patient_data.append({
            'ParticipantBarcode': barcode,
            'histological_type': hist_type
        })

print('__RESULT__:')
print(json.dumps({
    'total_female_brca': len(patient_data),
    'sample_patient': patient_data[0] if patient_data else None
}))"}

